export default function ContactUs() {
  return (
    <section className="mx-auto w-full max-w-5xl px-6 pb-16">
      <div className="border-t border-white/30 pt-10">

        <div className="flex flex-col gap-10 md:flex-row md:items-start md:justify-between">

          <div className="flex flex-col items-center gap-3 shrink-0">
            <div className="h-44 w-44 overflow-hidden rounded-2xl border border-white/20 bg-white/5 sm:h-48 sm:w-48">
              <Image
                src="/image.png"
                alt="AIMS-DTU Logo"
                width={160}
                height={160}
                className="h-full w-full object-cover"
              />
            </div>
            <span className="text-sm font-medium tracking-widest text-white">
              AIMS-DTU
            </span>
          </div>

          <div className="flex flex-col gap-5">
            <h3 className="text-base font-semibold text-white">Contact Us</h3>
 
            <div className="flex items-center gap-3 text-sm text-white/80">
              <Mail size={16} className="shrink-0 text-white/60" />
              <a
                href="mailto:aims@dtu.ac.in"
                className="hover:text-white transition-colors"
              >
                aims@dtu.ac.in
              </a>
            </div>
 
            <div className="flex items-start gap-3 text-sm text-white/80">
              <MapPin size={16} className="shrink-0 text-white/60 mt-0.5" />
              <span>
                <strong className="text-white font-semibold">
                  Delhi Technological University,
                </strong>{" "}
                Shahbad Daulatpur, Rohini, Delhi 110042
              </span>
            </div>

            <div className="border-t border-white/15 pt-2" />

            <div className="flex gap-3">
              {[
                { label: "Instagram", Icon: InstagramIcon, href: "https://www.instagram.com/aimsdtu/" },
                { label: "LinkedIn", Icon: LinkedInIcon, href: "https://www.linkedin.com/company/aims-dtu/" },
                { label: "Discord", Icon: DiscordIcon, href: "https://discord.com/" },
              ].map(({ label, Icon, href }) => (
                <a
                  key={label}
                  aria-label={label}
                  href={href}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="w-[52px] h-[52px] flex items-center justify-center rounded-[10px] border border-white/25 text-white transition hover:bg-white/10 hover:border-white/50"
                >
                  <Icon />
                </a>
              ))}
            </div>
          </div>
        </div>
 
        {/* Bottom bar */}
        <div className="mt-10 border-t border-white/15 pt-5 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <p className="text-xs text-white/40">© 2026 AIMS DTU. All rights reserved.</p>
          <div className="flex gap-6 text-xs text-white/40">
            <a href="#" className="hover:text-white transition-colors">Privacy Policy</a>
            <a href="#" className="hover:text-white transition-colors">Terms of Service</a>
          </div>
        </div>
 
      </div>
    </section>
  );
}
